import { Meta } from 'metaowl'

export class AboutPage extends Component {
  static template = 'AboutPage'

  setup() {
    Meta.title('About - My App')
    Meta.description('Learn more about our company.')
    Meta.ogTitle('About Us')
    Meta.ogDescription('Learn more about our company.')
    Meta.ogImage('/images/about-og.png')
  }
}
